#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Serialize packet_id
        stream << packet_id;

        // Serialize username with length prefix
        stream << hexi::prefixed(username);

        // Serialize scores vector with count prefix followed by elements
        stream << hexi::prefixed(scores);

        // Serialize metadata as null-terminated string
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a buffer adaptor for the vector
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary stream using the adaptor
    hexi::binary_stream stream(adaptor);

    // Serialize the packet into the stream
    // Note: We need to create a non-const copy since serialise() is non-const
    NetworkPacket packet_copy = packet;
    packet_copy.serialise(stream);

    return buffer;
}
```

