#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket packet;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read packet_id
    packet.packet_id = stream.get<uint32_t>();

    // Read username using length prefix
    packet.username = stream.get<std::string>();

    // Read scores vector - first read count, then elements
    uint32_t score_count = stream.get<uint32_t>();
    packet.scores.resize(score_count);
    for (auto& score : packet.scores) {
        score = stream.get<uint32_t>();
    }

    // Read metadata as null-terminated string for zero-copy view
    auto metadata_view = stream.get<std::string_view>('\0');
    packet.metadata = std::string(metadata_view);

    // Skip any remaining padding bytes
    stream.skip(stream.remaining());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use span() for packet_id (first 4 bytes)
    auto packet_id_span = stream.span<4>();
    info.packet_id = *reinterpret_cast<const uint32_t*>(packet_id_span.data());

    // Read username using prefixed adaptor to get string_view
    info.username = stream.get<std::string_view>();

    // Skip scores vector - read count then skip the data
    uint32_t score_count = stream.get<uint32_t>();
    stream.skip(score_count * sizeof(uint32_t));

    return info;
}
```

This implementation uses the Hexi library to deserialize the network packet according to the specified requirements:

1. **`deserialize_packet`**:
   - Reads `packet_id` as a `uint32_t`
   - Reads `username` using Hexi's built-in length-prefixed string deserialization
   - Reads the score count, then reads each score individually into the vector
   - Reads `metadata` as a null-terminated string using `string_view` for zero-copy, then converts to `std::string`
   - Skips any remaining bytes in the buffer

2. **`extract_packet_info`**:
   - Uses `span<4>()` to get a zero-copy view of the first 4 bytes for `packet_id`
   - Uses Hexi's prefixed string adaptor to get a `string_view` of the username
   - Reads the score count and skips the corresponding number of bytes to avoid reading the actual scores

The code follows the Hexi library patterns shown in the provided code fragments, using `buffer_adaptor` and `binary_stream` for efficient deserialization.

