NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket packet;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read packet_id
    packet.packet_id = stream.get<uint32_t>();

    // Read username using length prefix
    packet.username = stream.get<std::string>();

    // Read scores vector - first read count, then elements
    uint32_t score_count = stream.get<uint32_t>();
    packet.scores.resize(score_count);
    for (auto& score : packet.scores) {
        score = stream.get<uint32_t>();
    }

    // Read metadata as null-terminated string for zero-copy view
    auto metadata_view = stream.get<std::string_view>('\0');
    packet.metadata = std::string(metadata_view);

    // Skip any remaining padding bytes
    stream.skip(stream.remaining());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use span() for packet_id (first 4 bytes)
    auto packet_id_span = stream.span<4>();
    info.packet_id = *reinterpret_cast<const uint32_t*>(packet_id_span.data());

    // Read username using prefixed adaptor to get string_view
    info.username = stream.get<std::string_view>();

    // Skip scores vector - read count then skip the data
    uint32_t score_count = stream.get<uint32_t>();
    stream.skip(score_count * sizeof(uint32_t));

    return info;
}

