Looking at the code fragments and the Hexi library usage, I can see that Hexi provides buffer adaptors and binary streams for zero-copy operations. Here's the implementation:

```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>
#include <algorithm>

struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor from the span for zero-copy operations
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    PacketHeader header;

    // Use the stream to read the header fields with zero-copy
    stream.get(header.version);
    stream.get(header.flags);
    stream.get(header.packet_id);

    return header;
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor from the span for zero-copy operations
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Get a view of the remaining buffer data
    auto remaining_data = stream.view();

    // Find the null terminator (delimiter)
    auto null_pos = std::find(remaining_data.begin(), remaining_data.end(), '\0');

    if (null_pos == remaining_data.end()) {
        // No null terminator found, return empty view or handle error
        return std::string_view();
    }

    // Calculate the length of the string (excluding the null terminator)
    size_t length = std::distance(remaining_data.begin(), null_pos);

    // Create a string_view from the buffer data with zero-copy
    return std::string_view(reinterpret_cast<const char*>(remaining_data.data()), length);
}
```

Alternative implementation using span operations directly (if you prefer not to use the stream interface):

```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>
#include <algorithm>

struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Use span's subspan to get a zero-copy view of the header data
    if (buffer.size() < sizeof(PacketHeader)) {
        // Handle error: buffer too small
        return PacketHeader{0, 0, 0};
    }

    // Create a zero-copy view of the header portion
    auto header_span = buffer.subspan(0, sizeof(PacketHeader));

    // Cast the span data to PacketHeader (zero-copy)
    const PacketHeader* header_ptr = reinterpret_cast<const PacketHeader*>(header_span.data());

    return *header_ptr;
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Find the null terminator in the buffer
    auto null_pos = std::find(buffer.begin(), buffer.end(), '\0');

    if (null_pos == buffer.end()) {
        // No null terminator found
        return std::string_view();
    }

    // Calculate the length of the string
    size_t length = std::distance(buffer.begin(), null_pos);

    // Create a zero-copy string_view from the buffer
    return std::string_view(reinterpret_cast<const char*>(buffer.data()), length);
}
```

Both implementations provide zero-copy operations as requested. The first version uses Hexi's stream interface which provides more safety and error handling, while the second version uses direct span operations which are more explicit. Choose the one that best fits your needs.

