bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create buffer adaptor for the vector
    hexi::buffer_adaptor adaptor(buffer);

    // Check available space before writing
    // We need space for: header (4 bytes) + container size (varint) + items (4 bytes each)
    size_t required_space = sizeof(header);

    // Calculate space needed for the container (size as varint + each item)
    if (!items.empty()) {
        // Estimate varint size for container length (max 5 bytes for uint32_t)
        size_t varint_size = 0;
        uint32_t size = static_cast<uint32_t>(items.size());
        do {
            varint_size++;
            size >>= 7;
        } while (size > 0);

        required_space += varint_size + (items.size() * sizeof(uint32_t));
    } else {
        // Empty container still needs 1 byte for size (0)
        required_space += 1;
    }

    // Check if we have enough space
    if (adaptor.available_write() < required_space) {
        return false; // Insufficient space
    }

    // Create binary stream for writing
    hexi::binary_stream stream(adaptor);

    // Write the header
    stream.put(header);

    // Write the container using write_container functionality
    stream.put(items); // This handles the size and each item

    // Return success if stream is still in good state
    return static_cast<bool>(stream);
}
