```cpp
#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>
#include <array>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    using namespace hexi;

    // Create a block allocator that manages uint32_t elements
    block_allocator<uint32_t, element_count> allocator;

    std::cout << "=== Block Allocator Free List Demonstration ===\n";
    std::cout << "Allocator capacity: " << element_count << " elements\n\n";

    // Demonstrate initial state
    std::cout << "1. Initial state:\n";
    std::cout << "   - Free list should contain all " << element_count << " blocks\n";
    std::cout << "   - Internally, push() has been called " << element_count << " times during construction\n\n";

    // Allocate some blocks (internally uses pop())
    std::array<uint32_t*, 3> allocated_blocks;

    std::cout << "2. Allocating 3 blocks (pop() from free list):\n";
    for (int i = 0; i < 3; ++i) {
        allocated_blocks[i] = allocator.allocate();
        *allocated_blocks[i] = i + 100; // Assign some values
        std::cout << "   Allocated block " << i << " at address: " 
                  << static_cast<void*>(allocated_blocks[i]) 
                  << " with value: " << *allocated_blocks[i] << "\n";
    }
    std::cout << "   - After allocation, free list has " << (element_count - 3) << " blocks remaining\n\n";

    // Deallocate one block (internally uses push())
    std::cout << "3. Deallocating middle block (push() to free list):\n";
    std::cout << "   Deallocating block at: " << static_cast<void*>(allocated_blocks[1]) << "\n";
    allocator.deallocate(allocated_blocks[1]);
    std::cout << "   - After deallocation, free list has " << (element_count - 2) << " blocks\n";
    std::cout << "   - The deallocated block is pushed to the head of free list\n\n";

    // Allocate again to show LIFO behavior (should get the recently freed block)
    std::cout << "4. Allocating new block (should get recently freed block due to LIFO):\n";
    uint32_t* new_block = allocator.allocate();
    *new_block = 999;
    std::cout << "   Allocated new block at: " << static_cast<void*>(new_block) 
              << " with value: " << *new_block << "\n";

    // Check if we got the same address (demonstrating LIFO behavior)
    if (new_block == allocated_blocks[1]) {
        std::cout << "   ✓ Confirmed: Got same address as recently freed block (LIFO behavior)\n";
    }
    std::cout << "   - Free list now has " << (element_count - 3) << " blocks\n\n";

    // Deallocate remaining blocks
    std::cout << "5. Deallocating all remaining blocks:\n";
    allocator.deallocate(allocated_blocks[0]);
    allocator.deallocate(allocated_blocks[2]);
    allocator.deallocate(new_block);
    std::cout << "   - All blocks returned to free list via push()\n";
    std::cout << "   - Free list now has all " << element_count << " blocks again\n\n";

    // Demonstrate allocation pattern after multiple deallocations
    std::cout << "6. Demonstrating free list LIFO ordering:\n";

    // Allocate 3 blocks
    uint32_t* blocks[3];
    for (int i = 0; i < 3; ++i) {
        blocks[i] = allocator.allocate();
        *blocks[i] = i * 10;
    }

    // Deallocate in order: block0, block1, block2
    std::cout << "   Deallocating in order: block0 → block1 → block2\n";
    allocator.deallocate(blocks[0]);
    allocator.deallocate(blocks[1]);
    allocator.deallocate(blocks[2]);

    // Allocate 3 blocks - should get in reverse order: block2, block1, block0
    std::cout << "   Allocating 3 blocks - should get: block2 ← block1 ← block0 (LIFO)\n";
    uint32_t* reallocated[3];
    for (int i = 0; i < 3; ++i) {
        reallocated[i] = allocator.allocate();
    }

    // Verify LIFO order
    if (reallocated[0] == blocks[2] && reallocated[1] == blocks[1] && reallocated[2] == blocks[0]) {
        std::cout << "   ✓ Confirmed LIFO behavior: blocks returned in reverse allocation order\n";
    }

    // Cleanup
    for (int i = 0; i < 3; ++i) {
        allocator.deallocate(reallocated[i]);
    }

    std::cout << "\n=== Demonstration Complete ===\n";
    std::cout << "Summary: The block allocator uses a LIFO free list managed by:\n";
    std::cout << "  - push(): Adds freed blocks to the head of the free list\n";
    std::cout << "  - pop(): Removes and returns the head block for allocation\n";
    std::cout << "This provides O(1) allocation/deallocation with cache-friendly behavior.\n";
}

// Example usage
int main() {
    demonstrate_block_allocator_behavior<10>();
    return 0;
}
```

This implementation demonstrates how the `block_allocator` internally manages its free list using `push()` and `pop()` operations, even though these methods are private. The demonstration shows:

1. **Initialization**: The allocator starts with all blocks in the free list
2. **Allocation**: Uses `pop()` internally to remove blocks from the head of the free list
3. **Deallocation**: Uses `push()` internally to add blocks back to the head of the free list
4. **LIFO Behavior**: Shows that recently freed blocks are the first to be reallocated
5. **Cache Efficiency**: The LIFO pattern tends to be cache-friendly

The code includes detailed comments explaining how each operation corresponds to the internal free list management and verifies the expected LIFO behavior through address comparison.

