template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    std::vector<uint8_t> result;

    // Calculate available data to read
    size_t available_data = 0;
    if (storage.write_offset >= storage.read_offset) {
        available_data = storage.write_offset - storage.read_offset;
    } else {
        available_data = block_size - storage.read_offset + storage.write_offset;
    }

    // Limit preview to available data
    size_t bytes_to_copy = std::min(bytes_to_preview, available_data);
    result.reserve(bytes_to_copy);

    // Copy data without advancing read pointer
    size_t current_read_pos = storage.read_offset;
    for (size_t i = 0; i < bytes_to_copy; ++i) {
        result.push_back(static_cast<uint8_t>(storage.storage[current_read_pos]));
        current_read_pos = (current_read_pos + 1) % block_size;
    }

    return result;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;

    // Calculate readable size
    if (storage.write_offset >= storage.read_offset) {
        status.readable_size = storage.write_offset - storage.read_offset;
    } else {
        status.readable_size = 1024 - storage.read_offset + storage.write_offset;
    }

    // Calculate free space (total capacity minus readable size)
    status.free_space = 1024 - status.readable_size;

    return status;
}

