```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Create a file buffer for reading
    hexi::file_buffer buffer(file_path);

    // Determine how much we can actually read (min of requested bytes and available data)
    size_t actual_bytes_to_read = std::min(bytes_to_read, buffer.size());

    // Create a vector to hold the data
    std::vector<uint8_t> data(actual_bytes_to_read);

    // Read the data from the file buffer
    if (actual_bytes_to_read > 0) {
        buffer.read(data.data(), actual_bytes_to_read);
    }

    return data;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Create a file buffer for reading
    hexi::file_buffer buffer(file_path);

    // Determine how much we can actually preview (min of requested bytes and available data)
    size_t actual_bytes_to_preview = std::min(bytes_to_preview, buffer.size());

    // Create a vector to hold the data
    std::vector<uint8_t> data(actual_bytes_to_preview);

    // Preview the data from the file buffer without advancing the read pointer
    if (actual_bytes_to_preview > 0) {
        // Use copy to preview without modifying read position
        buffer.copy(data.data(), actual_bytes_to_preview);
    }

    return data;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Create a file buffer for writing
    // Note: The file_buffer constructor with just path likely opens for reading by default
    // We may need to specify write mode, but based on the test fragments, it seems to support writing
    hexi::file_buffer buffer(file_path);

    // Write the data to the file buffer
    if (!data.empty()) {
        buffer.write(data.data(), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    // Create a file buffer and get its size
    hexi::file_buffer buffer(file_path);
    return buffer.size();
}
