TEST(FileBuffer, PreviewFileHeader) {
    std::filesystem::path test_file = "test_header.bin";
    std::vector<uint8_t> test_data = {0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08};
    create_test_file(test_file, test_data);

    auto header = preview_file_header(test_file, 4);

    EXPECT_EQ(4, header.size());
    EXPECT_EQ(0x01, header[0]);
    EXPECT_EQ(0x02, header[1]);
    EXPECT_EQ(0x03, header[2]);
    EXPECT_EQ(0x04, header[3]);

    std::filesystem::remove(test_file);
}

TEST(FileBuffer, PreviewHeaderMultipleTimes) {
    std::filesystem::path test_file = "test_header2.bin";
    std::vector<uint8_t> test_data = {10, 20, 30, 40, 50};
    create_test_file(test_file, test_data);

    // Preview should not advance read pointer, so multiple calls should return same data
    auto header1 = preview_file_header(test_file, 3);
    auto header2 = preview_file_header(test_file, 3);

    EXPECT_EQ(header1, header2);
    EXPECT_EQ(3, header1.size());
    EXPECT_EQ(10, header1[0]);
    EXPECT_EQ(20, header1[1]);
    EXPECT_EQ(30, header1[2]);

    std::filesystem::remove(test_file);
}

