std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Create a file buffer to read the file
    hexi::file_buffer file(file_path);

    // Create a binary stream from the file buffer
    hexi::binary_stream stream(file);

    // Get the current read position to restore later
    auto original_pos = stream.tell();

    // Read the header data
    std::vector<uint8_t> header_data(header_size);
    stream.read(header_data.data(), header_size);

    // Restore the original read position
    stream.seek(original_pos);

    return header_data;
}

