TEST(StaticBuffer, WriteAndRead) {
    hexi::static_buffer<std::byte, 1024> buffer;
    std::vector<uint8_t> test_data = {1, 2, 3, 4, 5};

    write_data_to_buffer(buffer, test_data);
    auto result = read_data_from_buffer(buffer, test_data.size());

    EXPECT_EQ(test_data, result);
}

TEST(StaticBuffer, WriteMultipleTimes) {
    hexi::static_buffer<std::byte, 1024> buffer;
    std::vector<uint8_t> data1 = {10, 20, 30};
    std::vector<uint8_t> data2 = {40, 50, 60};

    write_data_to_buffer(buffer, data1);
    write_data_to_buffer(buffer, data2);

    auto result1 = read_data_from_buffer(buffer, data1.size());
    auto result2 = read_data_from_buffer(buffer, data2.size());

    EXPECT_EQ(data1, result1);
    EXPECT_EQ(data2, result2);
}

TEST(StaticBuffer, ReadWriteEmpty) {
    hexi::static_buffer<std::byte, 1024> buffer;
    std::vector<uint8_t> empty_data;

    write_data_to_buffer(buffer, empty_data);
    auto result = read_data_from_buffer(buffer, 0);

    EXPECT_TRUE(result.empty());
}

