    std::vector<uint8_t> result;
    result.reserve(bytes_to_copy);

    // Copy data from the buffer starting from current read position
    for (size_t i = 0; i < bytes_to_copy; ++i) {
        // Access data at current read position + i without advancing the read pointer
        result.push_back(static_cast<uint8_t>(buffer[i]));
    }

    return result;
}
