        // If there are more bytes to write, set the continuation bit
        if (value > 0) {
            byte |= 0x80;  // Set the MSB to indicate more bytes follow
        }

        writer.write_byte(byte);
        bytes_written++;
    }

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    T result = 0;
    int shift = 0;

    while (true) {
        if (reader.state() != hexi::detail::stream_state::ok) {
            break;
        }

        uint8_t byte = reader.read_byte();

        // Add the lower 7 bits to the result
        result |= static_cast<T>(byte & 0x7F) << shift;
        shift += 7;

        // If the MSB is not set, this is the last byte
        if ((byte & 0x80) == 0) {
            break;
        }

        // Safety check: prevent shift overflow for the type T
        if (shift >= static_cast<int>(sizeof(T) * 8)) {
            // This would overflow the target type
            if (reader.allow_throw()) {
                throw std::overflow_error("Varint value too large for target type");
            }
            break;
        }
    }

    return result;
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Create a writer and encode the value
    hexi::pmc::binary_stream_writer writer(adaptor);
    encode_varint<T>(writer, original_value);

    // Check if encoding was successful
    if (writer.state() != hexi::detail::stream_state::ok) {
        return false;
    }

    // Create a reader and decode the value
    hexi::pmc::buffer_adaptor read_adaptor(buffer);
    hexi::pmc::binary_stream_reader reader(read_adaptor);
    T decoded_value = decode_varint<T>(reader);

    // Check if decoding was successful
    if (reader.state() != hexi::detail::stream_state::ok) {
        return false;
    }

    // Compare the original and decoded values
    return original_value == decoded_value;
}

