```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create a write adaptor for the buffer
    hexi::pmc::buffer_write_adaptor write_adaptor(buffer);

    // Check available space before writing
    if (write_adaptor.free() < input_data.size()) {
        // If not enough space, resize the buffer (this is a simple approach)
        buffer.resize(buffer.size() + input_data.size());
        // Recreate the adaptor after resize
        write_adaptor = hexi::pmc::buffer_write_adaptor(buffer);
    }

    // Write the input data to the buffer
    write_adaptor.write(input_data.data(), input_data.size());

    // Create a read adaptor for the same buffer
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer);

    // Check the readable size
    std::size_t readable_size = read_adaptor.size();
    std::vector<uint8_t> output_data(readable_size);

    // Read the data back from the buffer
    if (readable_size > 0) {
        read_adaptor.read(output_data.data(), readable_size);
    }

    return output_data;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create a read adaptor for the buffer data
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer_data);

    // Get the current read pointer
    const uint8_t* read_ptr = read_adaptor.read_ptr();

    // Create a vector to hold the peeked data
    std::vector<uint8_t> peeked_data;

    // Use copy() to peek at data without advancing the read pointer
    if (peek_size > 0 && read_adaptor.size() >= peek_size) {
        peeked_data.resize(peek_size);
        read_adaptor.copy(peeked_data.data(), peek_size);

        // Now actually read (consume) the data to advance the pointer
        read_adaptor.read(nullptr, peek_size); // Read and discard to advance pointer
    }

    return peeked_data;
}
