std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_write_adaptor adaptor(buffer);

    for (const auto& chunk : chunks) {
        // Check available space before each write
        if (adaptor.free() < chunk.size()) {
            // If not enough space, resize the buffer to accommodate the chunk
            buffer.resize(buffer.size() + chunk.size());
            // Recreate adaptor after resize to ensure it's synchronized
            adaptor = hexi::pmc::buffer_write_adaptor(buffer);
        }
        adaptor.write(chunk.data(), chunk.size());
    }

    return adaptor.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    std::vector<uint8_t> result;
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    while (adaptor.size() > 0) {
        // Read only a portion of available data
        std::size_t read_size = std::min(chunk_size, adaptor.size());
        std::vector<uint8_t> chunk(read_size);
        adaptor.read(chunk.data(), read_size);

        // Append the read chunk to result
        result.insert(result.end(), chunk.begin(), chunk.end());

        // Check remaining data after each read
        // The loop continues until buffer is empty
    }

    return result;
}
